 1	import React, { FC } from 'react';
 2	
 3	import SectionWithSwitch from '@kubevirt-utils/components/SectionWithSwitch/SectionWithSwitch';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { Stack, StackItem, Title } from '@patternfly/react-core';
 6	
 7	import usePreviewFeaturesData from './hooks/usePreviewFeaturesData';
 8	import PreviewFeaturesPopover from './PreviewFeaturesPopover';
 9	
10	import './PreviewFeatures.scss';
11	
12	const PreviewFeaturesTab: FC = () => {
13	  const { t } = useKubevirtTranslation();
14	
15	  const { features } = usePreviewFeaturesData();
16	
17	  return (
18	    <>
19	      <Title headingLevel="h5">
20	        {t('Preview features')}
21	        <PreviewFeaturesPopover />
22	      </Title>
23	      <Stack hasGutter>
24	        <StackItem isFilled>
25	          {t(
26	            'Preview features are for testing purposes and should not be used in production environments.',
27	          )}
28	        </StackItem>
29	        {features.map((feature) => (
30	          <StackItem isFilled key={feature.id}>
31	            <SectionWithSwitch
32	              externalLink={feature.externalLink}
33	              id={feature.id}
34	              maxWidth="350px"
35	              switchIsOn={feature.featureEnabled}
36	              title={feature.label}
37	              turnOnSwitch={feature.toggleFeature}
38	            />
39	          </StackItem>
40	        ))}
41	      </Stack>
42	    </>
43	  );
44	};
45	
46	export default PreviewFeaturesTab;

